## Mock Session Testing

Since we can't easily run SSH servers in tests, we mock sessions:

```rust
/// Mock SSH session for testing
struct MockSession {
    pty: Option<Pty>,
    command: Vec<String>,
    user: String,
    env: HashMap<String, String>,
    output: Vec<u8>,
}

impl Session for MockSession {
    fn pty(&self) -> (Option<&Pty>, bool) {
        (self.pty.as_ref(), self.pty.is_some())
    }

    fn command(&self) -> &[String] {
        &self.command
    }
    // ... etc
}

/// Test middleware with mock session
#[test]
fn test_activeterm_middleware() {
    let middleware = activeterm::middleware();
    let handler = middleware(|_| Box::pin(async { /* final handler */ }));

    // Test with PTY
    let session_with_pty = MockSession::new().with_pty(Pty::default());
    let mut called = false;
    handler(session_with_pty).await;
    assert!(called, "Handler should be called with PTY");

    // Test without PTY
    let session_no_pty = MockSession::new();
    handler(session_no_pty).await;
    // Handler should NOT be called
}
```

## Middleware Order Test

```rust
/// Verify middleware execution order matches Go
#[test]
fn test_middleware_execution_order() {
    let order = Arc::new(Mutex::new(Vec::new()));

    let mw1 = {
        let order = order.clone();
        middleware(move |next| {
            let order = order.clone();
            move |s| {
                order.lock().push("mw1_before");
                next(s);
                order.lock().push("mw1_after");
            }
        })
    };

    let mw2 = { /* similar */ };
    let mw3 = { /* similar */ };

    let handler = compose_middleware(vec![mw1, mw2, mw3], final_handler);
    handler(mock_session).await;

    // Go order: mw3_before, mw2_before, mw1_before, handler, mw1_after, mw2_after, mw3_after
    let expected = vec!["mw3_before", "mw2_before", "mw1_before", "handler", "mw1_after", "mw2_after", "mw3_after"];
    assert_eq!(*order.lock(), expected);
}
```

